1	package com.sankuai.meituan.waimai.bizad.platform.billing.integration.sdf;
2	
3	import com.sankuai.meituan.waimai.bizad.billing.platform.vo.account.Result;
4	import com.sankuai.meituan.waimai.bizad.billing.platform.vo.sdf.SdfSignReq;
5	import com.sankuai.meituan.waimai.bizad.platform.billing.integration.sdf.base.SdfIntegrationBaseTest;
6	import org.junit.Test;
7	
8	import static org.junit.Assert.assertFalse;
9	import static org.junit.Assert.assertNotNull;
10	import static org.junit.Assert.assertTrue;
11	
12	/**
13	 * 集成测试：sdfSign — 随单返签约
14	 *
15	 * 接口：AdAccountService#sdfSign(SdfSignReq)
16	 *
17	 * 新增字段：
18	 *   - cashRatio (String): 商家在签约页选择的转入比例（仅 CUSTOM 自定义档位时有效）
19	 *
20	 * 签约时比例匹配逻辑（按 ratioMode 分支）：
21	 *   FIXED (0/null)  → 使用 activity.cash_ratio，忽略 req.cashRatio
22	 *   DYNAMIC (1)     → 查 wm_ad_sdf_ratio_config_future (status=1) 最新记录；无则用 activity.cash_ratio
23	 *   CUSTOM (2)      → req.cashRatio 非 null 时校验范围 max(1%, x-y%) ~ 50%；为 null 时查 status=1 最新；仍无则用 activity.cash_ratio
24	 *
25	 * 测试维度：
26	 *   TC01 - FIXED 模式，不传 cashRatio：使用 activity.cash_ratio
27	 *   TC02 - FIXED 模式，传 cashRatio：忽略 cashRatio，仍使用 activity.cash_ratio
28	 *   TC03 - DYNAMIC 模式，有 status=1 配置：使用配置比例
29	 *   TC04 - DYNAMIC 模式，无 status=1 配置：fallback 到 activity.cash_ratio
30	 *   TC05 - CUSTOM 模式，cashRatio 在范围内（如 "29.5"）：签约成功，立即生效
31	 *   TC06 - CUSTOM 模式，cashRatio 低于下限：返回错误
32	 *   TC07 - CUSTOM 模式，cashRatio 高于 50%：返回错误
33	 *   TC08 - CUSTOM 模式，cashRatio=null，有 status=1 配置：使用配置比例
34	 *   TC09 - CUSTOM 模式，cashRatio=null，无配置：fallback 到 activity.cash_ratio
35	 *   TC10 - 重复签约：幂等处理
36	 */
37	public class SdfSignTest extends SdfIntegrationBaseTest {
38	
39	    // ============================================================
40	    // TC01: FIXED 模式，不传 cashRatio
41	    // ============================================================
42	    @Test
43	    public void tc01_fixedMode_noCashRatio() {
44	        // given: wm_ad_sdf_activity.ratio_mode=0（FIXED），cash_ratio=30
45	        SdfSignReq req = buildSignReq(TEST_PARTNER_ID_FIXED, TEST_ACTIVITY_ID_FIXED, null);
46	
47	        // when
48	        Result result = adAccountService.sdfSign(req);
49	
50	        // then
51	        assertNotNull(result);
52	        assertTrue("FIXED 模式签约应成功", result.isSuccess());
53	        // verify DB: wm_ad_sdf_sign.cash_ratio_decimal=30
54	        // TODO: verifySignCashRatio(TEST_PARTNER_ID_FIXED, "30");
55	    }
56	
57	    // ============================================================
58	    // TC02: FIXED 模式，传 cashRatio（应被忽略）
59	    // ============================================================
60	    @Test
61	    public void tc02_fixedMode_withCashRatioIgnored() {
62	        // given
63	        SdfSignReq req = buildSignReq(TEST_PARTNER_ID_FIXED, TEST_ACTIVITY_ID_FIXED, "25");
64	
65	        // when
66	        Result result = adAccountService.sdfSign(req);
67	
68	        // then
69	        assertNotNull(result);
70	        assertTrue("FIXED 模式 cashRatio 应被忽略，签约成功", result.isSuccess());
71	        // verify DB: cash_ratio_decimal=30（activity.cash_ratio，忽略了传入的 "25"）
72	        // TODO: verifySignCashRatio(TEST_PARTNER_ID_FIXED, "30");
73	    }
74	
75	    // ============================================================
76	    // TC03: DYNAMIC 模式，有 status=1 配置
77	    // ============================================================
78	    @Test
79	    public void tc03_dynamicMode_hasRatioConfig() {
80	        // given: wm_ad_sdf_activity.ratio_mode=1（DYNAMIC），activity.cash_ratio=30
81	        //        wm_ad_sdf_ratio_config_future: partner_id=TEST_PARTNER_ID_DYNAMIC, status=1, cash_ratio=28
82	        SdfSignReq req = buildSignReq(TEST_PARTNER_ID_DYNAMIC_UNSIGNED, TEST_ACTIVITY_ID_DYNAMIC, null);
83	
84	        // when
85	        Result result = adAccountService.sdfSign(req);
86	
87	        // then
88	        assertNotNull(result);
89	        assertTrue("DYNAMIC 模式有 status=1 配置，签约应成功", result.isSuccess());
90	        // verify DB: cash_ratio_decimal=28（来自 ratio_config_future）
91	        // TODO: verifySignCashRatio(TEST_PARTNER_ID_DYNAMIC_UNSIGNED, "28");
92	    }
93	
94	    // ============================================================
95	    // TC04: DYNAMIC 模式，无 status=1 配置
96	    // ============================================================
97	    @Test
98	    public void tc04_dynamicMode_noRatioConfig_fallback() {
99	        // given: ratio_mode=1，无 status=1 的 ratio_config_future 记录
100	        SdfSignReq req = buildSignReq(TEST_PARTNER_ID_DYNAMIC_NO_CONFIG, TEST_ACTIVITY_ID_DYNAMIC, null);
101	
102	        // when
103	        Result result = adAccountService.sdfSign(req);
104	
105	        // then
106	        assertNotNull(result);
107	        assertTrue("DYNAMIC 模式无配置应 fallback 到 activity.cash_ratio 成功签约", result.isSuccess());
108	        // verify DB: cash_ratio_decimal=30（activity.cash_ratio）
109	    }
110	
111	    // ============================================================
112	    // TC05: CUSTOM 模式，cashRatio 在范围内
113	    // ============================================================
114	    @Test
115	    public void tc05_customMode_ratioInRange() {
116	        // given: ratio_mode=2, x=30, y=1.0 → ratioMin=max(1%, 29%)=29%, ratioMax=50%
117	        SdfSignReq req = buildSignReq(TEST_PARTNER_ID_CUSTOM, TEST_ACTIVITY_ID_CUSTOM, "29.5");
118	
119	        // when
120	        Result result = adAccountService.sdfSign(req);
121	
122	        // then
123	        assertNotNull(result);
124	        assertTrue("CUSTOM 模式 cashRatio=29.5 在范围内，应签约成功", result.isSuccess());
125	        // verify DB: cash_ratio_decimal=29.5（立即生效）
126	    }
127	
128	    // ============================================================
129	    // TC06: CUSTOM 模式，cashRatio 低于下限
130	    // ============================================================
131	    @Test
132	    public void tc06_customMode_ratioBelowMin() {
133	        // given: ratioMin=29%, 传入 "28"
134	        SdfSignReq req = buildSignReq(TEST_PARTNER_ID_CUSTOM, TEST_ACTIVITY_ID_CUSTOM, "28");
135	
136	        // when
137	        Result result = adAccountService.sdfSign(req);
138	
139	        // then
140	        assertNotNull(result);
141	        assertFalse("CUSTOM 模式 cashRatio 低于下限应失败", result.isSuccess());
142	    }
143	
144	    // ============================================================
145	    // TC07: CUSTOM 模式，cashRatio 超过 50%
146	    // ============================================================
147	    @Test
148	    public void tc07_customMode_ratioAboveMax() {
149	        // given: 传入 "51"，超过 50% 上限
150	        SdfSignReq req = buildSignReq(TEST_PARTNER_ID_CUSTOM, TEST_ACTIVITY_ID_CUSTOM, "51");
151	
152	        // when
153	        Result result = adAccountService.sdfSign(req);
154	
155	        // then
156	        assertNotNull(result);
157	        assertFalse("CUSTOM 模式 cashRatio=51 超上限应失败", result.isSuccess());
158	    }
159	
160	    // ============================================================
161	    // TC08: CUSTOM 模式，cashRatio=null，有 status=1 配置
162	    // ============================================================
163	    @Test
164	    public void tc08_customMode_cashRatioNull_hasConfig() {
165	        // given: ratio_mode=2，有 status=1 的 ratio_config_future 记录 cash_ratio=29
166	        SdfSignReq req = buildSignReq(TEST_PARTNER_ID_CUSTOM_WITH_CONFIG, TEST_ACTIVITY_ID_CUSTOM, null);
167	
168	        // when
169	        Result result = adAccountService.sdfSign(req);
170	
171	        // then
172	        assertNotNull(result);
173	        assertTrue("CUSTOM 模式 cashRatio=null 且有 status=1 配置，应成功", result.isSuccess());
174	        // verify DB: cash_ratio_decimal=29
175	    }
176	
177	    // ============================================================
178	    // TC09: CUSTOM 模式，cashRatio=null，无配置
179	    // ============================================================
180	    @Test
181	    public void tc09_customMode_cashRatioNull_noConfig_fallback() {
182	        // given: ratio_mode=2，无 status=1 配置
183	        SdfSignReq req = buildSignReq(TEST_PARTNER_ID_CUSTOM_NO_CONFIG, TEST_ACTIVITY_ID_CUSTOM, null);
184	
185	        // when
186	        Result result = adAccountService.sdfSign(req);
187	
188	        // then
189	        assertNotNull(result);
190	        assertTrue("CUSTOM 模式 cashRatio=null 无配置应 fallback 到 activity.cash_ratio 成功", result.isSuccess());
191	        // verify DB: cash_ratio_decimal=activity.cash_ratio
192	    }
193	
194	    // ============================================================
195	    // TC10: 重复签约（幂等）
196	    // ============================================================
197	    @Test
198	    public void tc10_duplicateSign_idempotent() {
199	        // given: 已签约
200	        SdfSignReq req = buildSignReq(TEST_PARTNER_ID_FIXED_SIGNED, TEST_ACTIVITY_ID_FIXED, null);
201	
202	        // when
203	        Result result = adAccountService.sdfSign(req);
204	
205	        // then
206	        assertNotNull(result);
207	        // 幂等：成功或返回已签约提示，不抛异常
208	        // TODO: 根据实际业务逻辑确认是 success 还是特定错误码
209	    }
210	
211	    // ============================================================
212	    // Helpers
213	    // ============================================================
214	    private SdfSignReq buildSignReq(long partnerId, long activityId, String cashRatio) {
215	        SdfSignReq req = new SdfSignReq();
216	        req.setPartnerId(partnerId);
217	        req.setPartnerType(PARTNER_TYPE_POI);
218	        req.setActivityId(activityId);
219	        req.setOperateType(OPERATE_TYPE_SIGN);
220	        req.setCashRatio(cashRatio);
221	        return req;
222	    }
223	}
