31	    public static SdfBenefitRuleDTO convertToSdfBenefitRuleDTO(SdfBenefitRule rule) {
32	        if (rule == null) {
33	            return null;
34	        }
35	        SdfBenefitRuleDTO ruleDTO = new SdfBenefitRuleDTO();
36	        if (!CollectionUtils.isEmpty(rule.getSdfRedPackStageRules())) {
37	            List<SdfRedPackStageDTO> redPackStageDTOList = new ArrayList<>();
38	            for (SdfRedPackStage redPackStage : rule.getSdfRedPackStageRules()) {
39	                SdfRedPackStageDTO redPackStageDTO = new SdfRedPackStageDTO();
40	                redPackStageDTO.setRatio(redPackStage.getRatio().toString());
41	                redPackStageDTO.setStartOffsetDays(redPackStage.getStartOffsetDays());
42	                redPackStageDTO.setEndOffsetDays(redPackStage.getEndOffsetDays());
43	                redPackStageDTO.setStartDate(redPackStage.getStartDate() == null ? 0 : redPackStage.getStartDate());
44	                redPackStageDTO.setEndDate(redPackStage.getEndDate() == null ? 0 : redPackStage.getEndDate());
45	                redPackStageDTOList.add(redPackStageDTO);
46	            }
47	            ruleDTO.setSdfRedPackStageRules(redPackStageDTOList);
48	        }
49	        if (rule.getSdfCouponInfo() != null) {
50	            SdfCouponInfoDTO couponInfoDTO = new SdfCouponInfoDTO();
51	            couponInfoDTO.setCouponAmount(rule.getSdfCouponInfo().getCouponAmount());
52	            couponInfoDTO.setCouponTemplateId(rule.getSdfCouponInfo().getCouponTemplateId());
53	            couponInfoDTO.setCouponId(rule.getSdfCouponInfo().getCouponId() != null ? rule.getSdfCouponInfo().getCouponId() : 0);
54	            couponInfoDTO.setBenefitTemplateId(rule.getSdfCouponInfo().getBenefitTemplateId());
55	            ruleDTO.setSdfCouponInfo(couponInfoDTO);
56	        }
57	
58	        return ruleDTO;
59	    }
