195	    private Pair<JSONObject, JSONArray> buildEffectData(long wmPoiId, SdfActivityInfoDTO activityInfoDTO, SdfBalanceDTO sdfBalanceDTO) {
196	        try {
197	            SdfLaunchStrategyDTO sdfLaunchStrategyDTO = activityInfoDTO == null ? null : activityInfoDTO.getSdfLaunchStrategyDTO();
198	            int adProdType = sdfLaunchStrategyDTO == null ? 0 : sdfLaunchStrategyDTO.getAdProdType();
199	            ADBffEffectDataResp respHis = wmAdEffectDataProxy.getHisEffectData(wmPoiId, adProdType, sdfBalanceDTO.getSignSatrtDate(), sdfBalanceDTO.getSignEndDate());
200	            // adProdType的值来自于com.sankuai.meituan.waimai.ad.tools.constants.ADProdType，
201	            // com.sankuai.meituan.waimai.ad.tools.constants.ADProdType 和 com.sankuai.meituan.waimai.bizad.data.java.enums.homepage.AdProductType的枚举一致时可以使用AdProductType.getAdProductType
202	            GeneralEffectDataDTO respRt = wmAdEffectDataProxy.getRealTimeEffectData(wmPoiId, Integer.parseInt(DateUtils.getToday()), AdProductType.getAdProductType(adProdType));
203	            log.debug("buildEffectData respHis:{}, respRt:{}", respHis, respRt);
204	            ADBffEffectData hisTotal = respHis == null || respHis.getTotal() == null ? null : respHis.getTotal().getSelfData();
205	            List<ADBffEffectData> hisDetails = respHis == null || respHis.getDetails() == null || respHis.getDetails().getSelfData() == null ? Collections.emptyList() : respHis.getDetails().getSelfData();
206	
207	            JSONObject launchEffect = new JSONObject();
208	            int totalShowCount = hisTotal == null ? respRt.getShowCount() : hisTotal.getShowCount() + respRt.getShowCount();
209	            int totalClickCount = hisTotal == null ? respRt.getClickCount() : hisTotal.getClickCount() + respRt.getClickCount();
210	            
211	            launchEffect.put("showCount", totalShowCount);
212	            launchEffect.put("clickCount", totalClickCount);
213	            launchEffect.put("clickRate", calClickRate(totalClickCount, totalShowCount));
214	
215	            JSONArray launchEffectDetailArray = new JSONArray();
216	            // 添加历史数据
217	            for (ADBffEffectData detail : hisDetails) {
218	                JSONObject launchEffectDetail = new JSONObject();
219	                launchEffectDetail.put("showCount", detail.getShowCount());
220	                launchEffectDetail.put("clickCount", detail.getClickCount());
221	                launchEffectDetail.put("clickRate", calClickRate(detail.getClickCount(), detail.getShowCount()));
222	                launchEffectDetail.put("date", detail.getTime());
223	                launchEffectDetailArray.add(launchEffectDetail);
224	            }
225	            // 添加今日数据
226	            JSONObject launchEffectDetail = new JSONObject();
227	            launchEffectDetail.put("showCount", respRt.getShowCount());
228	            launchEffectDetail.put("clickCount", respRt.getClickCount());
229	            launchEffectDetail.put("clickRate", calClickRate(respRt.getClickCount(), respRt.getShowCount()));
230	            launchEffectDetail.put("date", DateUtils.getToday());
231	            launchEffectDetailArray.add(launchEffectDetail);
232	            return Pair.of(launchEffect, launchEffectDetailArray);
233	        } catch (Exception e) {
234	            log.error("buildEffectData error, wmPoiId:{}", wmPoiId, e);
235	        }
236	        return Pair.of(null, null);
237	    }
