239	    private String calClickRate(int clickCount, int showCount) {
240	        if (showCount <= 0) {
241	            return "0.00";
242	        }
243	         return BigDecimal.valueOf(clickCount).multiply(BigDecimal.valueOf(100))
244	                 .divide(BigDecimal.valueOf(showCount), 2, RoundingMode.HALF_UP)
245	                 .toPlainString();
246	    }
