248	    private String buildBenefitRuleText(JSONObject object, SdfBenefitRuleDTO rule, SdfActivityInfoDTO activityInfo) {
249	        if (rule == null) {
250	            return "";
251	        }
252	        StringBuilder ruleText = new StringBuilder();
