264	                            stageDTO.getStartOffsetDays(), stageDTO.getStartOffsetDays() + 1, stageDTO.getEndOffsetDays() + 1, stageDTO.getRatio()));
265	                } else if (stageDTO.getEndOffsetDays() == stageDTO.getStartOffsetDays()) {
266	                    ruleText.append(String.format("若您保持签约状态%s天，平台将在第%s天为您发放每笔订单收入（顾客商品实付金额）%s%%的红包作为奖励;",
267	                            stageDTO.getStartOffsetDays(), stageDTO.getStartOffsetDays() + 1, stageDTO.getRatio()));
268	                } else if (stageDTO.getEndOffsetDays() < 0) {
269	                    ruleText.append(String.format("若您保持签约状态%s天，平台将从第%s天开始每天为您发放每笔订单收入（顾客商品实付金额）%s%%的红包作为奖励;",
270	                            stageDTO.getStartOffsetDays(), stageDTO.getStartOffsetDays() + 1, stageDTO.getRatio()));
271	                } else {
272	                    ruleText.append(String.format("若您保持签约状态%s天，平台将在有效期内每天为您发放每笔订单收入（顾客商品实付金额）%s%%的红包作为奖励;",
273	                            stageDTO.getStartOffsetDays(), stageDTO.getRatio()));
274	                }
275	            }
