350	    private JSONArray buildFaq(JSONObject ruleObject, int launchProdType) {
351	        JSONArray array = ruleObject == null ? null : ruleObject.getJSONArray("faqDesc");
352	        if (array == null) {
353	            return null;
354	        }
355	        // lion配置的时候需按条件展示的fqa需要放在最后面，注意标题标号的跳跃问题
356	        Iterator<Object> iterator = array.iterator();
357	        while (iterator.hasNext()) {
358	            JSONObject item = (JSONObject) iterator.next();
359	            Integer allowProdType = item.getInteger("allowProdType");
360	            if (allowProdType != null && !allowProdType.equals(launchProdType)) {
361	                iterator.remove();
362	            }
363	        }
364	        return array;
365	    }
