393	    private String readTransferFeeRuleTemplate(JSONObject ruleObject, SdfRatioInfoDTO ratioInfo) {
394	        try {
395	            JSONObject transferFeeRule = ruleObject == null ? null : ruleObject.getJSONObject("transferFeeRule");
396	            if (transferFeeRule == null) {
397	                return getDefaultTransferFeeTemplate();
398	            }
399	            int mode = ratioInfo != null && ratioInfo.isSetRatioMode()
400	                    ? ratioInfo.getRatioMode() : SdfRatioModeEnum.FIXED.getMode();
401	            if (mode == SdfRatioModeEnum.DYNAMIC.getMode()) {
402	                return getFieldOrDefault(transferFeeRule, "dynamic", getDefaultTransferFeeTemplate());
403	            } else if (mode == SdfRatioModeEnum.CUSTOM.getMode()) {
404	                return getFieldOrDefault(transferFeeRule, "custom", getDefaultTransferFeeTemplate());
405	            } else {
406	                return getFieldOrDefault(transferFeeRule, "fixed", getDefaultTransferFeeTemplate());
407	            }
408	        } catch (Exception e) {
409	            log.warn("buildTransferFeeRule parse config failed, fallback", e);
410	            return getDefaultTransferFeeTemplate();
411	        }
412	    }
